import{_ as e,o as a,c as s,ag as r}from"./chunks/framework.OsDJF_Ea.js";const g=JSON.parse('{"title":"Billing Dashboard","description":"","frontmatter":{},"headers":[],"relativePath":"billing.md","filePath":"billing.md"}'),o={name:"billing.md"};function i(n,t,d,l,h,c){return a(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="billing-dashboard" tabindex="-1">Billing Dashboard <a class="header-anchor" href="#billing-dashboard" aria-label="Permalink to &quot;Billing Dashboard&quot;">​</a></h1><p>The Billing Dashboard queries <code>system.billing.usage</code> in your Databricks workspace and shows spend broken down by user, job, and workload type.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Unity Catalog <strong>System Tables</strong> must be enabled on your workspace</li><li>A SQL warehouse to run the billing query (auto-discovered if blank; configure with <code>catalystops.billing.warehouseId</code>)</li><li>Databricks connection configured (host + token)</li></ul><h2 id="opening-the-dashboard" tabindex="-1">Opening the Dashboard <a class="header-anchor" href="#opening-the-dashboard" aria-label="Permalink to &quot;Opening the Dashboard&quot;">​</a></h2><p>Run <strong>CatalystOps: Show Billing Dashboard</strong> from the Command Palette, or click <strong>Show Dashboard</strong> in the Billing sidebar panel.</p><p>On first open, CatalystOps asks for confirmation before running the SQL query against your warehouse — to avoid unexpected charges.</p><h2 id="time-ranges" tabindex="-1">Time Ranges <a class="header-anchor" href="#time-ranges" aria-label="Permalink to &quot;Time Ranges&quot;">​</a></h2><p>The dashboard supports four time ranges:</p><table tabindex="0"><thead><tr><th>Range</th><th>Description</th></tr></thead><tbody><tr><td><strong>Day</strong></td><td>Current calendar day</td></tr><tr><td><strong>Week</strong></td><td>Past 7 days</td></tr><tr><td><strong>Month</strong></td><td>Past 30 days</td></tr><tr><td><strong>Custom</strong></td><td>Date range picker</td></tr></tbody></table><h2 id="caching" tabindex="-1">Caching <a class="header-anchor" href="#caching" aria-label="Permalink to &quot;Caching&quot;">​</a></h2><p>Results are cached for <strong>1 hour</strong> to avoid redundant warehouse queries. Click <strong>Refresh</strong> to force a live query at any time.</p><p>You can also run <strong>CatalystOps: Refresh Billing Data</strong> from the Command Palette.</p><h2 id="actual-cost-after-serverless-runs" tabindex="-1">Actual Cost After Serverless Runs <a class="header-anchor" href="#actual-cost-after-serverless-runs" aria-label="Permalink to &quot;Actual Cost After Serverless Runs&quot;">​</a></h2><p>Optionally, CatalystOps can query actual DBU consumption from <code>system.billing.usage</code> after each serverless dry run:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;catalystops.cost.queryBillingUsage&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This gives you a real cost figure instead of the estimated rate.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>catalystops.billing.warehouseId</code></td><td><code>&quot;&quot;</code></td><td>SQL warehouse ID (auto-discovered if blank)</td></tr><tr><td><code>catalystops.cost.queryBillingUsage</code></td><td><code>false</code></td><td>Query billing after each serverless run</td></tr><tr><td><code>catalystops.cost.dbuRatePerHour</code></td><td><code>0.4</code></td><td>DBU rate ($/hr) for cluster cost estimation</td></tr><tr><td><code>catalystops.cost.serverlessRatePerHour</code></td><td><code>0.7</code></td><td>Effective hourly cost for serverless estimation</td></tr></tbody></table>`,19)])])}const p=e(o,[["render",i]]);export{g as __pageData,p as default};
